INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027a69e3c98b0941765897', '干净卫生
服务优质', '["https://dimg04.c-ctrip.com/images/0232h12000iarq7rp4099_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-04', '红棉大床套房', '套房', '家庭亲子', 9, 0, 1, 4, '["卫生状况","前台服务","客房服务"]'::jsonb, '卫生状况', '前台服务', '客房服务'),
('68027a69e3c98b0941765898', '房间挺宽敞的，而且双床跟孩子两人睡一床够用
服务：酒店服务一级棒，每人都是笑面迎人。
卫生：卫生打理的也非常干净，打扫阿姨看房间里有几束花，还很贴心的拿花瓶给装起来
设施：很有历史感，唯一不足就是房间墙面有点印', '["https://dimg04.c-ctrip.com/images/0230w12000f94skq1AD00_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000f94h4ce4A4D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000f94o5cv6AC0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-26', '花园双床房', '双床房', '家庭亲子', 105, 0, 1, 8, '["房间设施","客房服务","卫生状况"]'::jsonb, '房间设施', '客房服务', '卫生状况'),
('68027a69e3c98b0941765899', '挺好的
出行方便
房间还有个小客厅
就是卫生间离床挨的太近', '["https://dimg04.c-ctrip.com/images/0231612000hwpn0g4C4C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000hwpm7t7B436_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000hwq37k4C16C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000hwpgbo42590_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000hwpuzd8F84F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000hwpftup3A2C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000hwprjj2D880_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-19', '花园双床房', '双床房', '家庭亲子', 29, 0, 8, 4, '["房间设施","交通便利性"]'::jsonb, '房间设施', '交通便利性', NULL),
('68027a69e3c98b094176589a', '1、前台服务员Gilian很nice，服务态度很好，很耐心，感谢给我们升级房间。
2、其他服务员态度也很棒，每次见面都打招呼，还主动按电梯。
3、粤韵套房很赞，一房一厅，面积很大，设施很新。房间还赠送了行政礼遇，包含下午茶和晚间的happy hour，超级赞，家人都非常满意。
4、30楼旋转餐厅太棒了，慢悠悠旋转，早餐非常丰富，都很好吃，超出预期。
5、酒店后花园值得散步，打卡拍照，太美了。
6、酒店交通便捷，旁边就是淘金地铁口，去哪里都很方便，都能乘坐地铁到达。', '["https://dimg04.c-ctrip.com/images/0232x12000f9h8h1wEC8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000f9gviye687A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-26', '花园大床房', '大床房', '家庭亲子', 234, 1, 9, 9, '["前台服务","房间设施","交通便利性"]'::jsonb, '前台服务', '房间设施', '交通便利性'),
('68027a69e3c98b094176589b', '非常好，房间很大，近地铁口。', '["https://dimg04.c-ctrip.com/images/0231y12000hwjqqh60129_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-01-19', '粤韵双床套房', '套房', '家庭亲子', 14, 0, 13, 5, '["房间设施","交通便利性","整体满意度"]'::jsonb, '房间设施', '交通便利性', '整体满意度'),
('68027a69e3c98b094176589c', '24号退房，房间虽小，但东西很齐全，还有博物馆。30楼的欢乐时光，下午茶体验感都很好，服务非常棒！但是30楼的早餐服务不如1楼的早餐服务，服务员说话也不好听，一大早心情就把心情破坏了，体验感太不好了！所以我住了五天四晚，只去30楼吃了一次早餐。1楼的早餐服务就很棒，服务员也很有礼貌，引导完等你坐下来会很耐心的询问需要咖啡吗？如有需要他们会帮你打好送过来。总体来说，除了30楼那次早餐体验的不舒服，酒店的其他方面我都很喜欢。', '["https://dimg04.c-ctrip.com/images/0232a12000f8ptnvgC851_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000f8pl6ibE787_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000f8p5nfn23ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-25', '花园大床房', '大床房', '情侣出游', 212, 0, 3, 9, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027a69e3c98b094176589d', '不愧是老牌五星白金酒店，花园酒店非常值得入住，价格也非常实惠，性价比超级高。服务也好、设施设备也好都非常符合五星的标准。下次去还会首选花园酒店。', '["https://dimg04.c-ctrip.com/images/0233b12000g0d5cvgA602_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000g0d6rk85EF7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000g0d7bu6B5BE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-06', '花园大床房', '大床房', '家庭亲子', 72, 0, 15, 7, '["整体满意度","性价比","前台服务"]'::jsonb, '整体满意度', '性价比', '前台服务'),
('68027a69e3c98b094176589e', '设施：很有传统中式的风格，设施也很全面。

环境：酒店环境非常好，花园非常漂亮，酒店可探索的地方很多。

服务：服务很细心，刚好赶上中秋节，居然还有额外赠送的月饼。', '["https://dimg04.c-ctrip.com/images/0232v12000fltje545B7D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000fltlj2mC259_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000fltiw02B455_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-17', '花园大床房', '大床房', '情侣出游', 82, 0, 9, 7, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027a69e3c98b094176589f', '酒店位于广东省广州市越秀区环市东路368号, 邮编510064。帮朋友预定的，我已经支付了房费，但入驻时交了500押金，退房后就退回了。', '["https://dimg04.c-ctrip.com/images/0236512000gpok16h49A9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000gpocn9a2428_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000gpo58kr72FB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-16', '花园双床房', '双床房', '代人预订', 68, 0, 26, 4, '["退房/入住效率"]'::jsonb, '退房/入住效率', NULL, NULL),
('68027a75e3c98b09417658a0', '本次入住很满意，不愧是老牌五星级酒店，各方面都做的不错', '["https://dimg04.c-ctrip.com/images/0230312000hahv0082962_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-25', '花园双床房', '双床房', '其他', 27, 0, 6, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027a75e3c98b09417658a1', '在广州玩，做功课，按照酒店博物馆的顺序依次住了，白天鹅，中国大酒店，和花园酒店
总的体验下来，这家真的最最贴心，下次还会来的
金庸说来了这里如进荣国府，一楼大厅的红楼梦壁画确实美丽，前台办理入住的时候很贴心，回答也很耐心，这是唯一一家我们到了就能入住的，其他两家均要到两三点，说要打扫。接着酒店后面的花园很美，酒店的电梯很方便，房间布局合适，床品整洁，都没有出去玩就呆在酒店逛逛了，不累不热，另外酒店的早餐在一楼和顶楼，我们选择了顶楼的旋转餐厅，视野非常好，菜品很多，下次来想多吃些甜品', '["https://dimg04.c-ctrip.com/images/0236j12000euq2g20AB4E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000euqd25vADD6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000euq5sfk256B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000euq4u1806B4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000euq57ko693D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000euq9kn9C2AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000euq56t102B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000euq7tubF556_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000euq9knd38BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '红棉双床套房', '套房', '朋友出游', 243, 2, 22, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027a75e3c98b09417658a2', '非常喜欢花园的圣诞氛围。房间一如既往的温馨，干净。', '["https://dimg04.c-ctrip.com/images/0231r12000hg3kix4974C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-27', '红棉大床套房', '套房', '商务出差', 25, 0, 29, 6, '["整体满意度","卫生状况"]'::jsonb, '整体满意度', '卫生状况', NULL),
('68027a75e3c98b09417658a3', '环境很好 态度很棒', '["https://dimg04.c-ctrip.com/images/0232w12000i4b68y3D5B4_R_150_150_R5_Q70_D.png"]'::jsonb, 4.8, 4, '2025-01-28', '花园大床房', '大床房', '家庭亲子', 9, 0, 3, 3, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027a75e3c98b09417658a4', '环境一级棒', '["https://dimg04.c-ctrip.com/images/0236c12000icfb6ho8118_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-06', '花园双床房', '双床房', '家庭亲子', 5, 0, 5, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027a75e3c98b09417658a5', '来广州玩，最终选择广州花园酒店，因为它是白金五星级酒店，服务确实不错，进入酒店大堂的那一刻，就会让人肃然起敬，浓厚的艺术文化气息扑面而来。那一刻就觉得选对了，很值得！Echo非常热心的帮我们一家老小升级的房间，酒店服务也是相当贴心。', '["https://dimg04.c-ctrip.com/images/0233o12000f6iz83yEF0F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000f6j5nc94E31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000f6j3l9u6AA3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.3, 4, '2024-08-20', '花园大床房', '大床房', '家庭亲子', 116, 0, 16, 8, '["前台服务","整体满意度","性价比"]'::jsonb, '前台服务', '整体满意度', '性价比'),
('68027a75e3c98b09417658a6', '非常好的酒店，酒店员工热情周到，设施很好，老牌酒店的风格浓郁。酒店里的博物馆值得去参观，有机会还会再来住。', '["https://dimg04.c-ctrip.com/images/0233d12000ghjl8vmDFB3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000ghk6arl440A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000ghjt1cd9AD5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-11-04', '花园大床房', '大床房', '独自旅行', 53, 0, 17, 6, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027a75e3c98b09417658a7', '花园酒店值得一住，前台客房餐厅碰到的服务员都很专业认真态度热情。1楼的自助早餐和3楼广式早茶行政酒廊小点心都很好吃。下次有机会来广州还住你们家。', '["https://dimg04.c-ctrip.com/images/0232312000fz7liqhFE9E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000fz8ro4jE815_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000fz7w1tv49FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000fz7w3e4255B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000fz8jc4d75BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000fz86ote249E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-04', '花园双床房', '双床房', '家庭亲子', 72, 0, 12, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027a75e3c98b09417658a8', '携程的套餐很划算。前台的小姐姐们有求必应，碰到的每位员工都微笑打招呼，客房服务还能根据前一天的使用情况增加备品，非常人性化。除开我住的房型淋浴跟浴缸在一起老人使用不方便外，都十分满意！', '["https://dimg04.c-ctrip.com/images/0236h12000fbxhpnoC03A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000fbxac5c662B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000fbx4ns21E2C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000fbxcnuu0697_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000fbxazxz4267_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000fbx7cw58EAF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-08-31', '花园双床房', '双床房', '家庭亲子', 92, 0, 8, 9, '["性价比","前台服务","客房服务"]'::jsonb, '性价比', '前台服务', '客房服务'),
('68027a75e3c98b09417658a9', '90年代住过的酒店之一，如今依然保留如初，每一个空间有着满满的回忆。 30楼的行政酒廊每天有下午茶和happy hour，这里每一位员工都很友好，特别是Carrie，我们对她印象深刻，是一位不可多得的优秀员工。', '["https://dimg04.c-ctrip.com/images/0233h424x8w0tnipn93E8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-21', '花园双床房', '双床房', '商务出差', 105, 0, 1, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027a80e3c98b09417658aa', '老广来评一下～好久没来花园了，这次携程的套餐真的很给力，马上订了。结果原来花园的服务已经不太OK了～我们到前台，给了身份证之后，那个前台的男士很冷漠地让我们给500押金，说了房型，递了房卡。我就问，不是有花园小羊周边？
他：哦，是吗，然后才去找。接下来我再问，是有消费额度可以用晚餐吗。他继续冷漠说，你吃了告知服务员房号吧。（难道他不能说是的几个餐厅都可以）后来我只能留言问携程客服说是不是套餐的东西要让他们确认一遍，携程客服马上打去前台，没人接，我让客服不要打。算了，我们自己去日本餐厅问。

日餐东西OK，厨师很热情，服务员也可以，就是她们收桌很慢，会吃了很久的东西没位置放新的也不收。日餐带位小哥态度好。

房间中规中矩，干净，但是不新，有很多使用痕迹是打扫不了的。另外晚上11点多打电话想要个硬枕头也没人接电话……怎么会这样……

早餐我们选在桃源馆用，也不错～但是应该瀑布好吃点。退房还是要自己提醒前台我们是套餐有消费额度才行……哎，而且他从头到尾也没发现我是岭南会金卡，我理解携程订的不能用，但是对比洲际万豪等前台服务几乎为0……', '["https://dimg04.c-ctrip.com/images/0234p12000f62imgbA556_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000f62imgn8E55_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000f62j7i19865_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-08-18', '红棉大床套房', '套房', '情侣出游', 471, 5, 2, 8, '["前台服务","客房服务","卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况'),
('68027a80e3c98b09417658ab', '三十年再次进住该店，风采依然。对比同市一众豪华品牌，不遑多让。一次过品尝了桃园、锦鲤吧与茘湾亭的美酒佳肴。遗憾的是，玻璃窗密封胶老化且无窗把锁扣，让窗外噪音有机可乘，扰人清梦。', '["https://dimg04.c-ctrip.com/images/0233t12000fdikzty8851_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000fdinqu5A61F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-09-03', '红棉大床套房', '套房', '商务出差', 88, 0, 58, 9, '["餐饮设施","安静程度","房间设施"]'::jsonb, '餐饮设施', '安静程度', '房间设施'),
('68027a80e3c98b09417658ac', '房间很旧很小墙纸脏的，第一次服务人员给了一个带浴缸的房，淋雨要站到浴缸里去洗位置非常小，像三星级，不过经过沟通有更换！洗漱用品比较差，老酒店，酒店外观漂亮打卡地方多，就是外美内差表里不一', '["https://dimg04.c-ctrip.com/images/0236f12000f9tqmouE6FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000f9tqza8B3A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-08-27', '花园双床房', '双床房', '家庭亲子', 93, 0, 6, 8, '["房间设施","卫生状况","整体满意度"]'::jsonb, '房间设施', '卫生状况', '整体满意度'),
('68027a80e3c98b09417658ad', '老牌五星酒店，地理位置很好，设施的维护也不错。刚入住的时候，对于酒店的服务态度是很满意的，没想到住了三晚，遇到两个状况感受很差。其一是早餐，一楼瀑布餐厅和三十楼，菜式基本上都是牛肉为主，完全没有猪肉菜式，当然早餐也没有海鲜这类的，对于我们这样因为宗教信仰而不吃牛肉的人而言，连续三天早餐素食度过，酒店的介绍完全不提及这个部分，否则我们定然不选择这个酒店，真是悲哀！非常难以接受！其二是退房，前台小女孩连数学计数都困难，我们付了1500押金，主动告知用了20元饮料费，她的原话是“剩下的148元我们会到时候退，但是什么时候不知道”再追问又回应说“押金150元用20元剩下148”，这就是著名的花园酒店吗？退房8个多小时，发现押金没退回，刚才联系携程客服，进行投诉反馈，酒店回应明天中午退。这令人非常不解，花园酒店的服务效率和品质都这么低下了吗？！', '["https://dimg04.c-ctrip.com/images/0234d12000f6gpi70417F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000f6goqx24B95_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000f6gwd7o2482_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-08-19', '花园大床房', '大床房', '其他', 372, 2, 35, 9, '["餐饮设施","退房/入住效率","前台服务"]'::jsonb, '餐饮设施', '退房/入住效率', '前台服务'),
('68027a80e3c98b09417658ae', '暑期带娃出行，选了一圈最终选择了这家，果然没选错，设施和设备都是相当齐全，服务也是非常满意，泳池满足了小朋友游泳的的快乐！对于酒店不能只看新旧，主要看综合实力啊！房间有些旧算是瑕疵，但是综合评分不错的，推荐！', '["https://dimg04.c-ctrip.com/images/0236812000g0z2wc6635F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000g0zgmdm8C8A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-07', '花园双床房', '双床房', '家庭亲子', 104, 0, 30, 7, '["公共设施","整体满意度","房间设施"]'::jsonb, '公共设施', '整体满意度', '房间设施'),
('68027a80e3c98b09417658af', 'viria和eaco态度热情 办入住还送了新鲜康乃馨 酒店整个服务都有种如沐春风的感觉 房间不算很大 但床品枕头非常舒服 还送了欢迎水果 点心 酒店位置非常好 旁边就是地铁到哪都方便', '["https://dimg04.c-ctrip.com/images/0233012000fe7gw2y946F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000fe7mc5lD29A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-04', '花园双床房', '双床房', '朋友出游', 91, 0, 8, 8, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68027a80e3c98b09417658b0', '体验特别好，服务很细心，很愉快的入住
酒店环境特别好，服务非常细心周到，早餐，下午茶，傍晚微醺时光都是特别惊喜的服务，还有点心送到房间服务', '["https://dimg04.c-ctrip.com/images/0235u12000fx0js8d1F7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000fx13erbB7B4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000fwzqhb6B02D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-02', '花园双床房', '双床房', '家庭亲子', 69, 0, 4, 7, '["整体满意度","客房服务","餐饮设施"]'::jsonb, '整体满意度', '客房服务', '餐饮设施'),
('68027a80e3c98b09417658b1', '花艺环境佳，还能看到维波楼的收藏', '["https://dimg04.c-ctrip.com/images/0231r12000i555mygEF23_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000i5704fmE224_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000i56sxp23429_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000i56sxp4AA07_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-29', '花园大床房', '大床房', '代人预订', 16, 0, 5, 4, '["景观/朝向"]'::jsonb, '景观/朝向', NULL, NULL),
('68027a80e3c98b09417658b2', '房间比较小，如果白天长时间留在房间里感觉比较压抑，床是挺舒服的。酒店处于广州市中心商圈，交通还是挺方便的，工作人员也挺热情有礼貌，或许入住的客户中，国外客户在这个酒店的占比比较大，酒店各种服务都会不自觉的往国外客户倾斜，有感受到一定的区别对待。总的来说，还算可以的。', '["https://dimg04.c-ctrip.com/images/0230312000f86o6t228F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000f86eo8zFB20_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-23', '花园大床房', '大床房', '商务出差', 133, 0, 4, 7, '["房间设施","交通便利性","前台服务"]'::jsonb, '房间设施', '交通便利性', '前台服务'),
('68027a80e3c98b09417658b3', '优雅的环境配上舒缓的音乐，亲切又体贴的服务，希望能够一如既往的保持下去。
设施：设备还是稍微旧了一点。房间浴室和厕所屏风不太够用。', '["https://dimg04.c-ctrip.com/images/0234b12000g017dye2CAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000g01alek9D7A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000g019e4hBB3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000g01hbblD4D0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-10-06', '花园大床房', '大床房', '家庭亲子', 65, 0, 10, 6, '["房间设施","前台服务"]'::jsonb, '房间设施', '前台服务', NULL),
('68027a8be3c98b09417658b4', '服务很细致周到。
中秋节前一天入住，还在房间放了一盒月饼，很惊喜。小孩喜欢游泳，刚在泳池边的位置坐下，就送来了纯净水和浴巾。老牌的五星酒店，实至名归。', '["https://dimg04.c-ctrip.com/images/0230p12000flys9ye02CC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000flyst574CFD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000flyvmjiC0AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-17', '花园双床房', '双床房', '家庭亲子', 75, 0, 6, 8, '["前台服务","客房服务","公共设施"]'::jsonb, '前台服务', '客房服务', '公共设施'),
('68027a8be3c98b09417658b5', '多次来广州都住这里。服务很棒，晚上到酒店晚，Betty看带着孩子，立即帮升级了房型，很贴心的问候关心，给个赞！房间干净，整洁。入住的朋友不少，酒店有三个早餐点，还有个旋转餐厅，菜品中西合并，品种繁多。露台的泳池是孩子最喜欢的。', '["https://dimg04.c-ctrip.com/images/0235712000f5z9a61200F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-18', '花园大床房', '大床房', '家庭亲子', 113, 0, 4, 9, '["前台服务","卫生状况","餐饮设施"]'::jsonb, '前台服务', '卫生状况', '餐饮设施'),
('68027a8be3c98b09417658b6', '设施：五星级的标准，大厅非常奢华，虽然很多年了，但是维护的特别好
卫生：整体都很好，干净整洁
环境：环境在广州来说，算是天花板了 ，比较大气
服务：门童小哥比较帅气，前台接待美女也非常热心，为顾客引导非常耐心
因为老公是广州人 他一直对花园酒店有情怀，所以这次回来一定要住花园酒店，比较推荐！', '["https://dimg04.c-ctrip.com/images/0235g12000fbb77i1340A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000fbapke39348_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000fbb83e75980_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-30', '花园双床房', '双床房', '家庭亲子', 146, 0, 14, 8, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027a8be3c98b09417658b7', '广州花园酒店30楼行政酒廊的服务很赞很周到，到广州一定要来打卡这里的旋转餐厅，不但早餐丰富，下午茶也很美味。大赞几位美女，Carrie，Echo，Kitty，服务热情大方，笑容有感染力，真是一次身心愉悦的旅程，大大的推荐', '["https://dimg04.c-ctrip.com/images/0232x12000f3fdy8t1D0D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000f3fe2ln7A24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000f3f3gtk8F35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000f3fbcfz13F5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 110, 1, 2, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027a8be3c98b09417658b8', '卫生： 洗手间与沐浴间共用一扇玻璃门，如果要沐浴就影响了洗手间的使用，没法同时使用，环境很好，大堂富丽堂皇 设施很好，服务态度很好 地理位置很好，出行方便 ，是一次很好的入住体验。', '["https://dimg04.c-ctrip.com/images/0231f12000f8wu0aqBF69_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-25', '花园双床房', '双床房', '家庭亲子', 90, 0, 19, 7, '["房间设施","整体满意度","交通便利性"]'::jsonb, '房间设施', '整体满意度', '交通便利性'),
('68027a8be3c98b09417658b9', '40年前人们印象中的位于广州环市东路的花园酒店是一间超豪华的五星级酒店。其实历经四十年沧桑变化的今天，店内大多数的房间已经残旧不堪，非常落后 ！只有少数几年前重新装修的红棉套房和粤韵套房可以入住。房间面积狭窄，住进去很不舒服！洗手间阵阵霉味散发出来，厕所和洗漱间共用一扇趟门，关了厕所门，洗漱间的门就只能敞开，极不方便，还有，进入厕所后侧着身体才能把门关上。全广州26家五星级酒店都住过了，这里的性价比最低！
        大堂再豪华都无用，房间环境和设施才是住客的首要所在 ！', '["https://dimg04.c-ctrip.com/images/0235i12000f3nseqqA5EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000f3n1l13BAD4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000f3nh8u65271_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2024-08-13', '花园双床房', '双床房', '其他', 240, 4, 10, 9, '["房间设施","性价比","卫生状况"]'::jsonb, '房间设施', '性价比', '卫生状况'),
('68027a8be3c98b09417658ba', '服务周到规范，环境优美，位置优越，早餐品类丰富。尤其是那两个瀑布，让人印象深圳。美中不足的是，充电插口太少，卫生间没有放手机的架子。', '["https://dimg04.c-ctrip.com/images/0230712000fu0q07w2B3E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000fu0c3vv604D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000fu0zkpt4F6B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000fu0xyeo0DB5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000fu0xx20AD33_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000fu0l82f5179_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-09-29', '红棉大床套房', '套房', '家庭亲子', 66, 0, 81, 7, '["房间设施","整体满意度","餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施'),
('68027a8be3c98b09417658bb', '非常有年代和历史沉淀感的一家酒店，我呢，怀着对参观历史建筑一份期望入住此酒店。但却是我入住所有五星酒店里面体验感比较差的，我说的是前台和餐厅的服务，并不包括客房等服务，还有硬件维护的也不错。总结体验如下，1、之前订的房间是18到21层，而且当天一再要求高楼层，但是晚上我夫人过来取卡的时候却给了个第7层低楼层，后通过携程的交涉很圆满的解决了，但是现场服务人员却轻描淡写的说可能交接的时候有误，这是你们老牌五星酒店不应该的啊，虽然后面送了宝格丽的洗护小包装；2、第二天吃早餐的时候由于人多，服务员让我夫人去排队。排就排呗，但排队的同时，有一个非洲的朋友过来以后在门口停留了会，和领班聊了会，竟然直接由领班带进去了，当时我们就提出质疑，领班尽然信誓旦旦的说他的朋友已经在里面了，这就是空口说白话，实际上最后这个非洲的朋友是单独一张桌子（大家懂得都懂）。后来领班又说他们是一个团队的，所以可以不用排队，我们直接回复他-就算是一个团队有朋友在里面也不能代排队代占座、除非你们是一个房间的才可以，现在都什么时代了，尽然还有这种事情发生[尴尬]3、自助早餐品种少、味道一般、性价比不高、而且问现场的面点（下面条混沌）师傅、这个蒸点是酒店包的还是外面采购的？面点师傅含糊其辞打太极说不知道要问厨师，晕，本来准备入住三天的，最后第三天（前面二天已经付款无法退）果断退房换了天河的酒店（扇子??）4、第三天早餐的时候也是排队，发现已经没有人押队了，秩序井井有条；5、客房服务不错，衣服洗的很干净（但价格比三亚丽思高30%，当天就干了1100洗衣）；6、硬件维护的不错，也很大气，可以看出当初设计的前卫和投入；希望花园酒店能够适当提升下服务水准，国人与外国人统一对待！如果没有上述1、2条，则酒店还是很完美的体验', '["https://dimg04.c-ctrip.com/images/0201512000f31r4ml65F2_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0233g12000f31nky6A2BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000f31jf4t46A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000f31dg8fC5BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000f31nbqv544A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000f31gw3x2B55_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-08-11', '花园双床房', '双床房', '家庭亲子', 746, 5, 23, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027a8be3c98b09417658bc', '酒店不错，续住了，周边景点很多', '["https://dimg04.c-ctrip.com/images/0233p12000hkn1qf15507_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000hkmi42jDACF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000hkmoejv83F0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-03', '花园双床房', '双床房', '家庭亲子', 15, 0, 7, 4, '["周边配套","整体满意度"]'::jsonb, '周边配套', '整体满意度', NULL),
('68027a8be3c98b09417658bd', '因为订的酒店出了点问题，改住的花园酒店，老牌五星级，服务不错，设施比较老旧，没有现代感，厕所和浴室只能关一边门。但是酒店整体感觉还是很不错的，瀑布孩子很喜欢，每次回酒店都要去逛一逛，双床拼起来很大，我们两大两小睡着还挺宽敞，有儿童洗漱用品。最惊喜的是，酒店送来的生日蛋糕！', '["https://dimg04.c-ctrip.com/images/0235212000f3krnuu5C09_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000f3kmmhxB425_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000f3kb954E523_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 136, 1, 10, 8, '["房间设施","整体满意度","前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务'),
('68027a97e3c98b09417658be', '酒店酒店位置离地铁机场都很近，高峰期间能订到距离不远交通也方便的酒店确实不容易，这家酒店相当不错，很感谢前台灵灵邀请我们过来行政酒廊，这里的服务让我感觉到非常的温馨，一进来Aimee就很热情的跟我们打招呼，Echo也非常热情的询问我们要喝些什么，需不需要中式点心，非常的热情，Kitty笑容也很甜美，这是我们旅行中最难忘的体验之一，强烈推荐任何人', '["https://dimg04.c-ctrip.com/images/0234g12000f3gnqik66BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000f3gus2uF90C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000f3gz63s1DB4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-12', '花园双床房', '双床房', '其他', 173, 1, 2, 9, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68027a97e3c98b09417658bf', '酒店早餐的瀑布景色怡人，吃早餐心情好。酒店在老城区，交通方便，边上就是地铁站。附近美食多，只觉得卫生间做成封闭式就更好了。', '["https://dimg04.c-ctrip.com/images/0235y12000g1dl8au025B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-10-08', '花园双床房', '双床房', '家庭亲子', 61, 0, 8, 7, '["餐饮设施","交通便利性","周边配套"]'::jsonb, '餐饮设施', '交通便利性', '周边配套'),
('68027a97e3c98b09417658c0', '酒店非常漂亮，地理位置佳，作为名副其实的五星级酒店，服务和设施非常棒，映入眼帘的大堂红楼梦主题的烫金壁画彰显酒店地位和独特气质。特别感谢前台办理入住的小姐姐，服务态度极其专业，笑容温暖人心，见我带娃出行，为我们升了套房，特别棒，而且早餐有三个餐厅可以选择，自助餐吃得比较多，尝试了三楼粤式茶点早餐，米其林级的餐饮品质让人印象深刻，孩子非常喜欢。早餐后逛了漂亮的后花园，喂了锦鲤，逛了园子，看了瀑布，美不胜收。这次广州之行花园酒店给我留下了特别棒的印象，下次来广州我一定继续选择入住花园酒店。', '["https://dimg04.c-ctrip.com/images/0234112000f3fhbvo9F2C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000f3fmd3zBFE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000f3fh2ru5DF4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000f3fejc1CFD6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000f3fnrksADBB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 245, 0, 2, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027a97e3c98b09417658c1', '花园真的名副其实 挺适合带老人孩子 我妈妈非常喜欢 四楼还有一个博物馆 花园很大非常漂亮 拍照很好看 一楼进门就不停的哇 看点评说房间有味道 入住后并没有 可能回南天会有一点吧 房间总体很大格局设置很好 美中不足的是硬件设施略微陈旧 床边的音响感觉很古老 现在都用蓝牙了 淋浴花洒有点难拧 最不好的就是马桶了 不是智能马桶倒是无所谓 但是不能连个阻尼都没有 第一次放下马桶圈 嗙好大一声 吓一大跳 然后每一次都要提醒自己小心翼翼 马桶的抽水按键对美甲很不友好 而且需要按好久才能抽干净 太旧了 前台入住的时候可以主动多一些酒店的介绍就好了 每个楼层都有一个管家小姐姐 服务很好  入住的时候酒店有个打卡活动 很好的一个活动但是酒店并没有介绍和告知 还是看了小红书才知道的 总体来说很不错 瑕不掩瑜 下次还住', '["https://dimg04.c-ctrip.com/images/0236e12000f0jycmpAF72_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000f0jkj7rA3B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000f0jzxfy55AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000f0jybza1BEA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000f0joipt8418_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000f0jqya40BF4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000f0k3mve9DD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000f0jybze315C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000f0jxl6v9CB7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-05', '红棉双床套房', '套房', '家庭亲子', 353, 0, 8, 9, '["房间设施","整体满意度","前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务'),
('68027a97e3c98b09417658c2', '补充一下，一定要在瀑布餐厅用个餐，这种感觉真的只有这一家。我女儿很喜欢花园，以后还会下榻，他说这里比长隆睡得好、吃的好。唯独就是不要睡在修路那一侧，真的真的很吵，是你睡不着的那种。泳池的蓝色水很好玩。感受一下吧', '["https://dimg04.c-ctrip.com/images/0233r12000f4uld0s7A6B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000f4uc9qcC0F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000f4uinly2335_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-15', '红棉大床套房', '套房', '家庭亲子', 105, 0, 20, 8, '["餐饮设施","安静程度","公共设施"]'::jsonb, '餐饮设施', '安静程度', '公共设施'),
('68027a97e3c98b09417658c3', '花园酒店很美，酒店内好多外国人，但各种服务都很到位，因为楼下在施工，但一点不影响入住的体验，Mandy的服务也很好，总体来说比较满意的一次入住～', '["https://dimg04.c-ctrip.com/images/0236412000j88068nD932_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000j87m92l0C7A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-21', '花园大床房', '大床房', '情侣出游', 72, 0, 15, 6, '["整体满意度","前台服务","安静程度"]'::jsonb, '整体满意度', '前台服务', '安静程度'),
('68027a97e3c98b09417658c4', '生日布置敷衍就算了(用的塑料花瓣铺床上），卫生还差，床上居然有包装残物。', '["https://dimg04.c-ctrip.com/images/0236a12000gpqkc1899CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000gppvmkm5444_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2024-11-16', '红棉大床套房', '套房', '独自旅行', 36, 10, 2, 7, '["卫生状况","客房服务"]'::jsonb, '卫生状况', '客房服务', NULL),
('68027a97e3c98b09417658c5', '环境不错，大堂金碧辉煌，有那种old money的感觉，那个人造瀑布呢，就是个噱头，个人觉得近看有点山寨，酒店博物馆值得一看，登记就行不用门票。位置也不错，去永庆坊、北京路还都挺方便的，唯一吐槽的是早餐，就是比较适合外国人（土耳其）人的菜式，如果你想尝试广式餐点的建议还是去对面的广州酒家或者酒店里面就有个餐厅。', '["https://dimg04.c-ctrip.com/images/0231g12000f4msf570702_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000f4mglxkF706_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000f4m3ac45349_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-15', '花园大床房', '大床房', '家庭亲子', 156, 0, 13, 8, '["周边配套","餐饮设施","整体满意度"]'::jsonb, '周边配套', '餐饮设施', '整体满意度'),
('68027a97e3c98b09417658c6', '酒店很豪华很漂亮，可是入住体验却很差，是最后两天客房服务人员优秀的服务态度给加了分。
入住体验差是因为下订单时就要求无烟房，办入住时还特意强调因为带孩子需要安静一点的房间，谁知第一天早上7点就给外面施工地方打地的声音吵醒，以为是不巧碰到，谁知第二天又是这样，本来游玩就很累还每天一早就吵醒太难受了，只能立马投诉要求换房，（虽然这种施工不是酒店发生的行为但是酒店人员肯定知道那些房间外面施工会影响到客户，而且是在特意要求需要安静环境下还这样安排就不合理了）
虽然客房服务态度很好立马就安排了，但是定房时酒店显示楼层应该是26-28层，入住就只给安排了14层，换房后更低了就12楼，一进门客厅就是一股烟味，这下好了，特意要求避开的两点全给我安排上了??????
原来想着这次入住体验太糟糕了，在这种不爽的情绪下却碰到了一个超级细心的客服服务人员，不但给孩子拿来了儿童洗漱用品（第一天和第二天根本没有孩子的洗漱用品）还贴心的把化妆品全部摆列整齐，更是知道房间有烟味后把空气净化器搬来消除味道，更感动的是还手写了留言，为这糟糕的心情增添了很多美好。
所以如果要评价的话酒店给50分，客房人员给100分。', '["https://dimg04.c-ctrip.com/images/0232k12000f2enk46BDFC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000f2dy1fqEF20_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-08-10', '红棉大床套房', '套房', '家庭亲子', 497, 3, 6, 9, '["客房服务","安静程度","卫生状况"]'::jsonb, '客房服务', '安静程度', '卫生状况'),
('68027a97e3c98b09417658c7', '酒店给升级了套房，小孩很高兴，缺点是套房没有浴缸，不能尽情地耍了，酒店泳池没有儿童的设施，小孩玩了一会就没兴趣了，30楼的行政酒廊不错，酒店瀑布餐厅挺有特色，还有很多大锦鲤', '["https://dimg04.c-ctrip.com/images/0234j12000f9y8lvxD1A8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000f9xqxud6A29_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-27', '花园双床房', '双床房', '家庭亲子', 86, 0, 1, 7, '["房间设施","公共设施","餐饮设施"]'::jsonb, '房间设施', '公共设施', '餐饮设施'),
('68027aa2e3c98b09417658c8', '第一次入住广州花园酒店，选择完全正确。大堂很宏伟，金碧辉煌。前台ECHO小姐姐看我们路途劳累，特意送了行政酒廊的下午茶，很贴心。我们在行政酒廊又遇到了一位印度小姐姐Carrie和Berrle,没有想到又是以为的惊喜，印度小姐姐中文很棒，一直在了解我们的需求，还邀请我们第二天下午可以继续去行政酒廊喝下午茶，还为我们预约了时间。因为我们有事去不了，感觉有点遗憾，喜欢花园酒店，下次我们会再次入住。再次感谢印度美女姐姐的热情服务。', '["https://dimg04.c-ctrip.com/images/0234u12000f0yumn28922_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000f0yujbwF8FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000f0yusngC63D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000f0yuuv23454_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000f0yuq1z2640_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000f0yuq29EF38_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-06', '红棉双床套房', '套房', '家庭亲子', 213, 1, 1, 9, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL)
 ON CONFLICT (_id) DO NOTHING;
